import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  inject,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ApiService, errorMessage } from '../core/api.service';
import { LEAD_STATUSES, Lead, LeadStatus } from '../core/models';

@Component({
  selector: 'app-leads',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './leads.component.html',
  styleUrl: '../shared/list.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class LeadsComponent implements OnInit {
  private readonly api = inject(ApiService);
  readonly statuses = LEAD_STATUSES;

  loading = signal(true);
  error = signal<string | null>(null);
  saving = signal(false);

  leads = signal<Lead[]>([]);

  name = signal('');
  company = signal('');
  email = signal('');
  status = signal<LeadStatus>('New');

  async ngOnInit(): Promise<void> {
    this.loading.set(true);
    try {
      this.leads.set(await this.api.listLeads());
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not load leads.'));
    } finally {
      this.loading.set(false);
    }
  }

  async create(): Promise<void> {
    this.error.set(null);
    if (!this.name().trim()) {
      this.error.set('Name is required.');
      return;
    }
    this.saving.set(true);
    try {
      const created = await this.api.createLead({
        name: this.name().trim(),
        email: this.email().trim() || undefined,
        status: this.status(),
      });
      // `company` is a UI-only field the backend does not persist; keep the
      // entered value on the optimistic row so the table stays informative.
      const lead = { ...created, company: this.company().trim() };
      this.leads.update((list) => [lead, ...list]);
      this.name.set('');
      this.company.set('');
      this.email.set('');
      this.status.set('New');
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not create the lead.'));
    } finally {
      this.saving.set(false);
    }
  }
}
